  NAND_X1 U2 ( .A(PLow), .B(PHi), .Z(n6) );
  NAND_X1 U3 ( .A(n5), .B(n4), .Z(Gout) );
  NAND_X1 U4 ( .A(GLow), .B(PHi), .Z(n4) );
  INV_X1 U5 ( .A(GHi), .Z(n5) );
endmodule


